import heapq

def func(lists, k):
    # Count frequencies of all integers across all lists
    freq = {}
    for lst in lists:
        for num in lst:
            freq[num] = freq.get(num, 0) + 1

    # Use a min-heap to keep track of the k most frequent elements
    # We store tuples of (-frequency, number) to simulate a max-heap for frequency
    heap = []
    for num, count in freq.items():
        heapq.heappush(heap, (-count, num))

    # Pop the k elements with highest frequencies
    result = []
    for _ in range(k):
        if not heap:
            break
        neg_count, num = heapq.heappop(heap)
        result.append(num)

    return result

